import List

class Solution:
    def search(self, nums: List[int], target: int) -> int:
        left, right = 0, len(nums) - 1

        while left <= right:
            mid = left + (right - left) // 2

            if nums[mid] == target:
                return mid

            # Determine which half is sorted
            # Case 1: Left half is sorted
            if nums[left] <= nums[mid]:
                # Check if target is in the sorted left half
                if nums[left] <= target < nums[mid]:
                    right = mid - 1  # Target is in the left half, so search there
                else:
                    left = mid + 1   # Target is not in the left half, search the right (rotated) half
            # Case 2: Right half is sorted
            else: # nums[mid] < nums[right]
                # Check if target is in the sorted right half
                if nums[mid] < target <= nums[right]:
                    left = mid + 1   # Target is in the right half, so search there
                else:
                    right = mid - 1  # Target is not in the right half, search the left (rotated) half

        return -1
```

