from typing import List

class Solution:
    def onesMinusZeros(self, grid: List[List[int]]) -> List[List[int]]:
        m = len(grid)
        n = len(grid[0])

        # Precompute counts for rows
        # onesRow[i] stores the number of ones in row i
        # zerosRow[i] stores the number of zeros in row i
        onesRow = [0] * m
        zerosRow = [0] * m
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    onesRow[i] += 1
                else:
                    zerosRow[i] += 1

        # Precompute counts for columns
        # onesCol[j] stores the number of ones in column j
        # zerosCol[j] stores the number of zeros in column j
        onesCol = [0] * n
        zerosCol = [0] * n
        for j in range(n):
            for i in range(m):
                if grid[i][j] == 1:
                    onesCol[j] += 1
                else:
                    zerosCol[j] += 1

        # Calculate the difference matrix
        diff = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                diff[i][j] = onesRow[i] + onesCol[j] - zerosRow[i] - zerosCol[j]

        return diff

