from typing import List

class Solution:
    def resultGrid(self, image: List[List[int]], threshold: int) -> List[List[int]]:
        m, n = len(image), len(image[0])

        # Initialize two grids:
        # `sum_val[i][j]` will store the sum of rounded-down average intensities of regions 
        # that pixel (i,j) belongs to.
        # `count_region[i][j]` will store the number of regions that pixel (i,j) belongs to.
        sum_val = [[0] * n for _ in range(m)]
        count_region = [[0] * n for _ in range(m)]

        # Iterate through all possible top-left corners of 3x3 subgrids
        for r in range(m - 2):
            for c in range(n - 2):
                # Check if the current 3x3 subgrid is a valid region
                is_valid_region = True
                current_region_sum = 0

                # Pixels in the 3x3 subgrid are from (r, c) to (r+2, c+2)

                # Check horizontal adjacencies
                for i in range(r, r + 3):
                    for j in range(c, c + 2):
                        if abs(image[i][j] - image[i][j+1]) > threshold:
                            is_valid_region = False
                            break
                    if not is_valid_region:
                        break

                if not is_valid_region:
                    continue # Not a valid region, move to next subgrid

                # Check vertical adjacencies
                for j in range(c, c + 3):
                    for i in range(r, r + 2):
                        if abs(image[i][j] - image[i+1][j]) > threshold:
                            is_valid_region = False
                            break
                    if not is_valid_region:
                        break

                if is_valid_region:
                    # If it's a valid region, calculate its average intensity
                    # Sum all 9 pixels
                    for i in range(r, r + 3):
                        for j in range(c, c + 3):
                            current_region_sum += image[i][j]

                    # Round down the average intensity for this region
                    region_avg_intensity = current_region_sum // 9

                    # Add this average intensity to sum_val for all pixels in this region
                    # And increment count_region for all pixels in this region
                    for i in range(r, r + 3):
                        for j in range(c, c + 3):
                            sum_val[i][j] += region_avg_intensity
                            count_region[i][j] += 1

        # Construct the final result grid
        result = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                if count_region[i][j] > 0:
                    # If pixel (i,j) belongs to one or more regions, 
                    # calculate the average of their rounded-down average intensities, rounded down.
                    result[i][j] = sum_val[i][j] // count_region[i][j]
                else:
                    # If pixel (i,j) does not belong to any region, its value is image[i][j].
                    result[i][j] = image[i][j]

        return result
