class Solution:
    def simplifyPath(self, path: str) -> str:
        stack = []
        # Split the path by '/' to get components.
        # The split() method on '/' will handle multiple consecutive slashes
        # by producing empty strings, which we filter out.
        # For example, "/a//b/" -> ["", "a", "", "b", ""].
        components = path.split('/')

        for comp in components:
            if comp == "" or comp == ".":
                # Ignore empty strings (from multiple slashes) and single periods (current directory).
                continue
            elif comp == "..":
                # If '..', pop the last directory from the stack if it's not empty.
                # Going up from root is not possible, so we just don't pop.
                if stack:
                    stack.pop()
            else:
                # For valid directory/file names, push them onto the stack.
                stack.append(comp)

        # Join the directories in the stack with '/' and prepend a '/'.
        # If the stack is empty (e.g., path was "/"), it means we are at the root.
        if not stack:
            return "/"
        else:
            return "/" + "/".join(stack)

