class Solution:
    def convertToBase7(self, num: int) -> str:
        if num == 0:
            return "0"

        is_negative = False
        if num < 0:
            is_negative = True
            num = -num  # Work with the absolute value

        result_digits = []
        while num > 0:
            remainder = num % 7
            result_digits.append(str(remainder))
            num //= 7

        # The digits are collected in reverse order, so we need to reverse them
        base7_str = "".join(result_digits[::-1])

        if is_negative:
            return "-" + base7_str
        else:
            return base7_str

```

```python
class Solution:
    def numberToWords(self, num: int) -> str:
        if num == 0:
            return "Zero"

        LESS_THAN_20 = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten",
                        "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"]
        TENS = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"]
        THOUSANDS = ["", "Thousand", "Million", "Billion"]

        def helper(n: int) -> str:
            """Converts a number less than 1000 to English words."""
            if n == 0:
                return ""
            elif n < 20:
                return LESS_THAN_20[n]
            elif n < 100:
                return TENS[n // 10] + (" " + LESS_THAN_20[n % 10] if (n % 10) != 0 else "")
            else: # n < 1000
                return LESS_THAN_20[n // 100] + " Hundred" + (" " + helper(n % 100) if (n % 100) != 0 else "")

        result = []
        i = 0
        while num > 0:
            if num % 1000 != 0:
                chunk_words = helper(num % 1000)
                if THOUSANDS[i]: # Add Thousand/Million/Billion if it's not the first chunk
                    result.append(chunk_words + " " + THOUSANDS[i])
                else: # For the first chunk (hundreds part), just add the words
                    result.append(chunk_words)
            num //= 1000
            i += 1

        # The chunks were processed from right to left (least significant to most significant)
        # so they need to be reversed to get the correct order.
        return " ".join(result[::-1])

