class Solution:
    def kthFactor(self, n: int, k: int) -> int:

        # Approach 1: Iterate from 1 to n to find factors
        # This approach naturally finds factors in ascending order.
        # We count them as we find them.

        factor_count = 0
        for i in range(1, n + 1):
            if n % i == 0:
                factor_count += 1
                if factor_count == k:
                    return i

        # If we finish the loop and haven't found the kth factor,
        # it means n has less than k factors.
        return -1

```

