class Solution:
    def capitalizeTitle(self, title: str) -> str:
        words = title.split(' ')
        result_words = []

        for word in words:
            if len(word) <= 2:
                # If the length of the word is 1 or 2 letters,
                # change all letters to lowercase.
                result_words.append(word.lower())
            else:
                # Otherwise, change the first letter to uppercase
                # and the remaining letters to lowercase.
                result_words.append(word[0].upper() + word[1:].lower())

        # Join the processed words back into a single string with spaces.
        return ' '.join(result_words)

